SELECT(xsd:integer(REPLACE(STR(?att) , "," , "")) AS ?attendance) WHERE {
  VALUES ?series {
    wd:Q4295899 wd:Q4630084 wd:Q56692089
  }
  {
    ?series wdt:P1344 wd:Q213959
  } UNION {
    ?series wdt:P1345 wd:Q213959
  } UNION {
    ?series wdt:P1346 wd:Q213959
  }
  ?series wdt:P527 ?game .
  ?game wdt:P1538 ?att .
  FILTER(isLiteral(?att) && REGEX(STR(?att) , "^[0-9,]+$"))
}
