SELECT(?hours * 60 + ?minutes AS ?total_minutes) WHERE {
  {
    ?game wdt:P750 wd:Q334634 .
    ?game wdt:P751 wd:Q650840 .
  } UNION {
    ?game wdt:P750 wd:Q650840 .
    ?game wdt:P751 wd:Q334634 .
  }
  ?game wdt:P2047 ?duration .
  BIND(xsd:integer(REPLACE(STR(?duration) , 'PT(\\\\d+)H.*' , '$1')) AS ?hours)
  .
  BIND(xsd:integer(REPLACE(STR(?duration) , '.*?(\\\\d+)M' , '$1')) AS ?minutes)
}
ORDER BY(?hours * 60 + ?minutes)
OFFSET 2
LIMIT 1

SELECT ?club(COUNT(?season) AS ?count) WHERE {
  VALUES ?club {
    wd:Q249679 wd:Q3044572
  }
  VALUES ?league {
    wd:Q447247 wd:Q17733
  }
  ?season wdt:P179 ?league .
  ?season wdt:P3967 ?finalEvent .
  ?finalEvent wdt:P1344 ?club .
}
GROUP BY ?club
ORDER BY DESC(?count)
LIMIT 1

SELECT ?races WHERE {
  ?season wdt:P31 wd:Q211975 ; wdt:P3924 wd:Q9673 ; wdt:P580 ?start ; wdt:P1113 ?races .
  FILTER(YEAR(?start) > 2015)
}
ORDER BY ASC(?races)
LIMIT 1

SELECT ?totalMinutes WHERE {
  {
    ?game wdt:P1444 wd:Q334634 .
    ?game wdt:P1445 wd:Q650840
  } UNION {
    ?game wdt:P1444 wd:Q650840 .
    ?game wdt:P1445 wd:Q334634
  }
  .
  ?game wdt:P2047 ?duration .
  BIND((COALESCE(REPLACE(?duration , '.*T([0-9]+)H.*' , '$1' , 'i') , 0) * 60 + COALESCE(REPLACE(?duration , '.*T([0-9]+)M.*' , '$1' , 'i') , 0)) AS ?totalMinutes)
}
ORDER BY ?totalMinutes
OFFSET 2
LIMIT 1

SELECT ?duration WHERE {
  {
    wd:Q2413623 p:P39 ?statement
  } UNION {
    wd:Q369770 p:P39 ?statement
  }
  ?statement ps:P39 ?position ; pq:P580 ?startTime ; pq:P582 ?endTime .
  BIND(xsd:integer(SUBSTR(STR(?endTime) , 1 , 4)) AS ?endYear)
  BIND(xsd:integer(SUBSTR(STR(?startTime) , 1 , 4)) AS ?startYear)
  BIND(?endYear - ?startYear AS ?duration)
  FILTER(?duration > 0)
}
ORDER BY DESC(?duration)
OFFSET 4
LIMIT 1

SELECT ?game ?attendance ?year WHERE {
  VALUES ?dodger {
    wd:Q334634
  }
  VALUES ?phillies {
    wd:Q650840
  }
  VALUES ?nlcs {
    wd:Q1363275
  }
  ?game wdt:P31 wd:Q7184551 ; wdt:P710 ?dodger ; wdt:P710 ?phillies ; wdt:P1216507 ?attendance ; wdt:P585 ?date .
  ?game wdt:P1995 / wdt:P31 ?nlcs .
  BIND(YEAR(?date) AS ?year)
  FILTER(?year IN(1977 , 1978 , 2008 , 2009))
}
ORDER BY ASC(?attendance)

