SELECT ?game ?attendance WHERE {
  ?series wdt:P361 wd:Q1363275 .
  ?series wdt:P585 ?date .
  FILTER(YEAR(?date) >= 1970 && YEAR(?date) <= 1979)
  {
    ?series wdt:P1346 wd:Q653772 ; wdt:P1451 wd:Q826751
  } UNION {
    ?series wdt:P1346 wd:Q826751 ; wdt:P1451 wd:Q653772
  }
  ?game wdt:P361 ?series .
  ?game(wdt:P1129 | wdt:P4989) ?attendance .
}
ORDER BY DESC(xsd:integer(?attendance))
LIMIT 1

SELECT ?attendance WHERE {
  ?edition wdt:P31 wd:Q1363275 .
  {
    ?edition wdt:P710 wd:Q334634 ; wdt:P710 wd:Q650840
  } UNION {
    ?edition wdt:P1346 wd:Q334634 ; wdt:P3457 wd:Q650840
  } UNION {
    ?edition wdt:P1346 wd:Q650840 ; wdt:P3457 wd:Q334634
  }
  ?game wdt:P361 ?edition .
  ?game wdt:P1110 | wdt:P1082 ?attendance .
  FILTER(isNumeric(?attendance) || REGEX(STR(?attendance) , '^\\d+,\\d+$'))
}
ORDER BY DESC(xsd:integer(REPLACE(STR(?attendance) , ',' , '')))
LIMIT 1

SELECT ?club ?appearances WHERE {
  VALUES ?club {
    wd:Q3044572 wd:Q2272176 wd:Q2521385
  }
  OPTIONAL {
    ?club wdt:P1273 ?wins
  }
  OPTIONAL {
    ?club wdt:P1114 ?losses
  }
  BIND((COALESCE(?wins , 0) + COALESCE(?losses , 0)) AS ?appearances)
  FILTER(?appearances > 0)
}
ORDER BY ASC(?appearances)
LIMIT 2
OFFSET 1

SELECT ?duration_minutes WHERE {
  VALUES ?dodgers {
    wd:Q334634
  }
  VALUES ?phillies {
    wd:Q650840
  }
  ?series wdt:P31 wd:Q1363275 ; wdt:P710 ?dodgers ; wdt:P710 ?phillies ; wdt:P527 ?game .
  ?game wdt:P2047 ?duration_seconds .
  FILTER(ISNUMERIC(?duration_seconds))
  BIND(?duration_seconds / 60 AS ?duration_minutes)
}
ORDER BY ?duration_seconds
OFFSET 4
LIMIT 1

SELECT ?team(COUNT(?event) AS ?count) WHERE {
  VALUES ?team {
    wd:Q249679 wd:Q2521385 wd:Q2272176
  }
  ?event wdt:P1344 ?team .
  ?event rdfs:label ?label .
  FILTER(LANG(?label) = 'en' && CONTAINS(LCASE(?label) , 'grand final'))
}
GROUP BY ?team
ORDER BY ASC(?count)
LIMIT 1
OFFSET 1

SELECT ?club ?clubLabel(COUNT(DISTINCT ?season) AS ?count) WHERE {
  VALUES ?club {
    wd:Q2521385 wd:Q249679 wd:Q2272176
  }
  ?club p:P166 ?stmt .
  ?stmt ps:P166 wd:Q2637699 .
  OPTIONAL {
    ?club rdfs:label ?clubLabel
    FILTER(lang(?clubLabel) = 'en')
  }
}
GROUP BY ?club ?clubLabel
ORDER BY DESC(?count)
LIMIT 1
